const express = require('express');
const crypto = require('crypto');
const url = require('url');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.urlencoded({ extended: true }));
app.use(bodyParser.json());

// In-memory stores
const authorizationCodes = new Map();
const accessTokens = new Map();
const refreshTokens = new Map();

// Registered clients
const clients = new Map([
  ['client123', {
    client_id: 'client123',
    client_secret: 'secret456',
    redirect_uris: ['http://localhost:3001/callback'],
    name: 'Test Application'
  }]
]);

// Simulated users
const users = new Map([
  ['user1', { id: 'user1', username: 'alice', password: 'password123', name: 'Alice Smith' }],
  ['user2', { id: 'user2', username: 'bob', password: 'password456', name: 'Bob Jones' }]
]);

// Sessions (simple in-memory)
const sessions = new Map();

// Helper: generate random string
function generateToken(length = 32) {
  return crypto.randomBytes(length).toString('hex');
}

// Helper: validate client
function validateClient(clientId, redirectUri) {
  const client = clients.get(clientId);
  if (!client) return null;
  if (redirectUri && !client.redirect_uris.includes(redirectUri)) return null;
  return client;
}

// Helper: validate redirect URI to prevent open redirect attacks
function isValidRedirectUri(redirectUri, client) {
  if (!redirectUri || !client) return false;

  try {
    const parsed = new URL(redirectUri);

    // Block javascript: and data: URIs
    if (['javascript:', 'data:', 'vbscript:'].includes(parsed.protocol)) {
      return false;
    }

    // Must exactly match one of the registered redirect URIs
    return client.redirect_uris.includes(redirectUri);
  } catch (e) {
    return false;
  }
}

// Middleware: simple session handling via cookie
function sessionMiddleware(req, res, next) {
  let sessionId = null;
  const cookieHeader = req.headers.cookie;
  if (cookieHeader) {
    const cookies = cookieHeader.split(';').reduce((acc, c) => {
      const [key, val] = c.trim().split('=');
      acc[key] = val;
      return acc;
    }, {});
    sessionId = cookies['session_id'];
  }

  if (sessionId && sessions.has(sessionId)) {
    req.session = sessions.get(sessionId);
    req.sessionId = sessionId;
  } else {
    sessionId = generateToken(16);
    req.session = {};
    req.sessionId = sessionId;
    sessions.set(sessionId, req.session);
    res.cookie('session_id', sessionId, { httpOnly: true, sameSite: 'lax' });
  }

  next();
}

app.use(sessionMiddleware);

