app.get('/authorize', (req, res) => {
  const {
    response_type,
    client_id,
    redirect_uri,
    scope,
    state
  } = req.query;

  // Validate response_type
  if (response_type !== 'code') {
    return res.status(400).json({
      error: 'unsupported_response_type',
      error_description: 'Only authorization code flow is supported'
    });
  }

  // Validate client
  const client = validateClient(client_id);
  if (!client) {
    return res.status(400).json({
      error: 'invalid_client',
      error_description: 'Unknown client_id'
    });
  }

  // Validate redirect_uri
  const effectiveRedirectUri = redirect_uri || client.redirect_uris[0];
  if (!isValidRedirectUri(effectiveRedirectUri, client)) {
    // Do NOT redirect to an invalid redirect_uri — show error directly
    return res.status(400).json({
      error: 'invalid_redirect_uri',
      error_description: 'The redirect_uri is not registered for this client'
    });
  }

  // Store authorization request in session
  req.session.authRequest = {
    response_type,
    client_id,
    redirect_uri: effectiveRedirectUri,
    scope: scope || 'read',
    state
  };
  sessions.set(req.sessionId, req.session);

  // If user is already logged in, show consent page
  if (req.session.userId) {
    const user = users.get(req.session.userId);
    return res.send(renderConsentPage(client, scope || 'read', user));
  }

  // Show login page
  res.send(renderLoginPage(client_id, effectiveRedirectUri, scope, state));
});

