app.post('/authorize/login', (req, res) => {
  const { username, password } = req.body;

  // Find user
  let foundUser = null;
  for (const [id, user] of users) {
    if (user.username === username && user.password === password) {
      foundUser = user;
      break;
    }
  }

  if (!foundUser) {
    return res.status(401).send(renderLoginPage(
      req.session.authRequest?.client_id,
      req.session.authRequest?.redirect_uri,
      req.session.authRequest?.scope,
      req.session.authRequest?.state,
      'Invalid username or password'
    ));
  }

  // Set user in session
  req.session.userId = foundUser.id;
  sessions.set(req.sessionId, req.session);

  // Check if we have a pending auth request
  if (!req.session.authRequest) {
    return res.status(400).json({ error: 'No pending authorization request' });
  }

  const client = clients.get(req.session.authRequest.client_id);
  res.send(renderConsentPage(client, req.session.authRequest.scope, foundUser));
});

