app.post('/authorize/consent', (req, res) => {
  const { consent } = req.body;
  const authRequest = req.session.authRequest;

  if (!authRequest) {
    return res.status(400).json({ error: 'No pending authorization request' });
  }

  if (!req.session.userId) {
    return res.status(401).json({ error: 'User not authenticated' });
  }

  const client = clients.get(authRequest.client_id);

  // Re-validate redirect_uri before redirecting
  if (!isValidRedirectUri(authRequest.redirect_uri, client)) {
    return res.status(400).json({
      error: 'invalid_redirect_uri',
      error_description: 'The redirect_uri is not valid'
    });
  }

  const redirectUri = new URL(authRequest.redirect_uri);

  if (consent !== 'allow') {
    // User denied - redirect with error
    redirectUri.searchParams.set('error', 'access_denied');
    redirectUri.searchParams.set('error_description', 'User denied the authorization request');
    if (authRequest.state) {
      redirectUri.searchParams.set('state', authRequest.state);
    }

    // Clean up session
    delete req.session.authRequest;
    sessions.set(req.sessionId, req.session);

    return res.redirect(redirectUri.toString());
  }

  // Generate authorization code
  const code = generateToken(16);
  const codeData = {
    code,
    client_id: authRequest.client_id,
    redirect_uri: authRequest.redirect_uri,
    user_id: req.session.userId,
    scope: authRequest.scope,
    created_at: Date.now(),
    expires_at: Date.now() + (10 * 60 * 1000), // 10 minutes
    used: false
  };

  authorizationCodes.set(code, codeData);

  // Build redirect URL with code
  redirectUri.searchParams.set('code', code);
  if (authRequest.state) {
    redirectUri.searchParams.set('state', authRequest.state);
  }

  // Clean up session
  delete req.session.authRequest;
  sessions.set(req.sessionId, req.session);

  console.log(`Authorization code issued: ${code} for user ${req.session.userId}`);
  res.redirect(redirectUri.toString());
});

