app.post('/token', (req, res) => {
  const { grant_type } = req.body;

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Supported grant types: authorization_code, refresh_token'
    });
  }
});

function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri, client_id, client_secret } = req.body;

  // Authenticate client
  // Support both body params and Basic auth
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [id, secret] = decoded.split(':');
    authenticatedClientId = decodeURIComponent(id);
    authenticatedClientSecret = decodeURIComponent(secret);
  }

  if (!authenticatedClientId || !authenticatedClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication required'
    });
  }

  const client = clients.get(authenticatedClientId);
  if (!client || client.client_secret !== authenticatedClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials'
    });
  }

  // Validate authorization code
  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required'
    });
  }

  const codeData = authorizationCodes.get(code);

  if (!codeData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid authorization code'
    });
  }

  // Prevent authorization code reuse (RFC 6749 Section 4.1.2)
  if (codeData.used) {
    // Code has been used before — revoke all tokens issued with this code
    console.warn(`Authorization code reuse detected: ${code}. Revoking associated tokens.`);

    // Revoke any access tokens issued from this code
    for (const [tokenKey, tokenData] of accessTokens) {
      if (tokenData.authorization_code === code) {
        accessTokens.delete(tokenKey);
        console.log(`Revoked access token: ${tokenKey}`);
      }
    }

    // Revoke any refresh tokens issued from this code
    for (const [tokenKey, tokenData] of refreshTokens) {
      if (tokenData.authorization_code === code) {
        refreshTokens.delete(tokenKey);
        console.log(`Revoked refresh token: ${tokenKey}`);
      }
    }

    // Remove the code itself
    authorizationCodes.delete(code);

    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used. All associated tokens have been revoked.'
    });
  }

  // Check expiration
  if (Date.now() > codeData.expires_at) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  // Verify client_id matches
  if (codeData.client_id !== authenticatedClientId) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client'
    });
  }

  // Verify redirect_uri matches
  if (codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used in the authorization request'
    });
  }

  // Mark code as used (instead of deleting, to detect reuse)
  codeData.used = true;
  codeData.used_at = Date.now();
  authorizationCodes.set(code, codeData);

  // Generate tokens
  const accessToken = generateToken(32);
  const refreshToken = generateToken(32);
  const expiresIn = 3600; // 1 hour

  accessTokens.set(accessToken, {
    token: accessToken,
    client_id: authenticatedClientId,
    user_id: codeData.user_id,
    scope: codeData.scope,
    authorization_code: code,
    created_at: Date.now(),
    expires_at: Date.now() + (expiresIn * 1000)
  });

  refreshTokens.set(refreshToken, {
    token: refreshToken,
    client_id: authenticatedClientId,
    user_id: codeData.user_id,
    scope: codeData.scope,
    authorization_code: code,
    created_at: Date.now(),
    expires_at: Date.now() + (30 * 24 * 60 * 60 * 1000) // 30 days
  });

  console.log(`Tokens issued for user ${codeData.user_id}, client ${authenticatedClientId}`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
}

function handleRefreshTokenGrant(req, res) {
  const { refresh_token, client_id, client_secret, scope } = req.body;

  // Authenticate client
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [id, secret] = decoded.split(':');
    authenticatedClientId = decodeURIComponent(id);
    authenticatedClientSecret = decodeURIComponent(secret);
  }

  if (!authenticatedClientId || !authenticatedClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication required'
    });
  }

  const client = clients.get(authenticatedClientId);
  if (!client || client.client_secret !== authenticatedClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials'
    });
  }

  if (!refresh_token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'refresh_token is required'
    });
  }

  const tokenData = refreshTokens.get(refresh_token);
  if (!tokenData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid refresh token'
    });
  }

  if (tokenData.client_id !== authenticatedClientId) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client'
    });
  }

  if (Date.now() > tokenData.expires_at) {
    refreshTokens.delete(refresh_token);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token has expired'
    });
  }

  // Validate scope (can only narrow, not broaden)
  const requestedScope = scope || tokenData.scope;
  const originalScopes = tokenData.scope.split(' ');
  const requestedScopes = requestedScope.split(' ');
  for (const s of requestedScopes) {
    if (!originalScopes.includes(s)) {
      return res.status(400).json({
        error: 'invalid_scope',
        error_description: 'Requested scope exceeds original grant'
      });
    }
  }

  // Rotate refresh token
  refreshTokens.delete(refresh_token);

  const newAccessToken = generateToken(32);
  const newRefreshToken = generateToken(32);
  const expiresIn = 3600;

  accessTokens.set(newAccessToken, {
    token: newAccessToken,
    client_id: authenticatedClientId,
    user_id: tokenData.user_id,
    scope: requestedScope,
    created_at: Date.now(),
    expires_at: Date.now() + (expiresIn * 1000)
  });

  refreshTokens.set(newRefreshToken, {
    token: newRefreshToken,
    client_id: authenticatedClientId,
    user_id: tokenData.user_id,
    scope: requestedScope,
    created_at: Date.now(),
    expires_at: Date.now() + (30 * 24 * 60 * 60 * 1000)
  });

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: requestedScope
  });
}

