// ============================================================
// Periodic cleanup of expired codes and tokens
// ============================================================
setInterval(() => {
  const now = Date.now();

  for (const [code, data] of authorizationCodes) {
    // Remove used codes after 5 minutes (enough time to detect reuse)
    // Remove expired codes
    if (now > data.expires_at + (5 * 60 * 1000)) {
      authorizationCodes.delete(code);
    }
  }

  for (const [token, data] of accessTokens) {
    if (now > data.expires_at) {
      accessTokens.delete(token);
    }
  }

  for (const [token, data] of refreshTokens) {
    if (now > data.expires_at) {
      refreshTokens.delete(token);
    }
  }
}, 60 * 1000); // Run every minute

